    // The state will be (current node, mask, charCounts)
    // mask is a bitmask representing visited nodes
    // charCounts is an array of 26 integers representing counts of each character in the path

    const queue = [];
    for (let i = 0; i < n; i++) {
        const mask = 1 << i;
        const charCounts = new Array(26).fill(0);
