        }
        if (oddCount <= 1 && totalLen > maxLen) {
            maxLen = totalLen;
        }

        // Explore neighbors
        for (const neighbor of adj[node]) {
            if (!(mask & (1 << neighbor))) {
                const newMask = mask | (1 << neighbor);
                const newCharCounts = [...charCounts];
                newCharCounts[label.charCodeAt(neighbor) - 97]++;
                queue.push([neighbor, newMask, newCharCounts]);
            }
        }
    }

    return maxLen;
