import scala.collection.mutable.Queue

def solve(n: Long, edges: Array[Array[Long]], label: String): Long = {
    val adj = Array.fill(n.toInt)(List.empty[Int])
    for (e <- edges) {
        val u = e(0).toInt
        val v = e(1).toInt
        adj(u) = v :: adj(u)
        adj(v) = u :: adj(v)
    }

    var maxLen = 1L

    case class State(node: Int, mask: Int, charCounts: Array[Int])

    val queue = Queue[State]()
    for (i <- 0 until n.toInt) {
        val mask = 1 << i
        val charCounts = Array.fill(26)(0)
        charCounts(label(i) - 'a') += 1
        queue.enqueue(State(i, mask, charCounts))
    }

    while (queue.nonEmpty) {
        val state = queue.dequeue()
        val charCounts = state.charCounts

        var oddCount = 0
        var totalLen = 0
        for (count <- charCounts) {
            totalLen += count
            if (count % 2 == 1) {
                oddCount += 1
            }
        }
        if (oddCount <= 1 && totalLen > maxLen) {
            maxLen = totalLen
        }

        for (neighbor <- adj(state.node)) {
            if ((state.mask & (1 << neighbor)) == 0) {
                val newMask = state.mask | (1 << neighbor)
                val newCharCounts = charCounts.clone()
                newCharCounts(label(neighbor) - 'a') += 1
                queue.enqueue(State(neighbor, newMask, newCharCounts))
            }
        }
    }

    maxLen
}
